// pageURL builds a pager href preserving all active filter fields. Page 1 is omitted from the URL.
func pageURL(page int, f store.IncidentFilter) string {
	v := url.Values{}
	if page > 1 {
		v.Set("page", fmt.Sprintf("%d", page))
	}
	if f.Phase != "" {
		v.Set("phase", f.Phase)
	}
	if f.Namespace != "" {
		v.Set("namespace", f.Namespace)
	}
	if f.Reason != "" {
		v.Set("reason", f.Reason)
	}
	if f.Query != "" {
		v.Set("q", f.Query)
	}
	if s := v.Encode(); s != "" {
		return "/?" + s
	}
	return "/"
}

// phaseURL builds a stat-card href for phase p while preserving namespace/reason/q.
// Phase is reset to 1 when switching; current page is intentionally dropped.
func phaseURL(phase string, f store.IncidentFilter) string {
	v := url.Values{}
	if phase != "" {
		v.Set("phase", phase)
	}
	if f.Namespace != "" {
		v.Set("namespace", f.Namespace)
	}
	if f.Reason != "" {
		v.Set("reason", f.Reason)
	}
	if f.Query != "" {
		v.Set("q", f.Query)
	}
	if s := v.Encode(); s != "" {
		return "/?" + s
	}
	return "/"
}

// phaseBadgeClass maps a phase string to its CSS class.
func phaseBadgeClass(phase string) string {
	switch phase {
	case "Done":
		return "badge-done"
	case "Partial":
		return "badge-partial"
	case "Failed":
		return "badge-failed"
	case "Diagnosing":
		return "badge-diagnosing"
	default:
		return "badge-pending"
	}
}

// phaseCardClass maps a phase string to its stat-card CSS class.
func phaseCardClass(phase string) string {
	switch phase {
	case "Done":
		return "stat-card-done"
	case "Partial":
		return "stat-card-partial"
	case "Failed":
		return "stat-card-failed"
	case "Diagnosing":
		return "stat-card-diagnosing"
	default:
		return "stat-card-pending"
	}
}

// statCardActiveClass returns the active CSS class when the card's phase matches the current filter.
func statCardActiveClass(phase, activePhase string) string {
	if phase == activePhase {
		return "stat-card-active"
	}
	return ""
}

